"""Chat database schema and core operations."""

from __future__ import annotations

import hashlib
import os
import sqlite3
import uuid
from datetime import datetime, timedelta, timezone
from pathlib import Path

CHAT_DB_PATH = Path(
    os.environ.get("CHAT_DB_PATH")
    or (Path(__file__).resolve().parent / "data" / "chat.db")
)

DEFAULT_MESSAGE_TTL_MIN = 60
DEFAULT_MEETUP_GRACE_MIN = 30


def _now() -> str:
    return datetime.now(timezone.utc).isoformat()


def _uuid() -> str:
    return str(uuid.uuid4())


def init_chat_db(db: sqlite3.Connection) -> None:
    db.execute("PRAGMA journal_mode=WAL")
    db.execute("PRAGMA busy_timeout=5000")
    db.execute("PRAGMA foreign_keys=ON")
    db.execute("PRAGMA secure_delete=ON")
    db.executescript("""
        CREATE TABLE IF NOT EXISTS users (
            id                 TEXT PRIMARY KEY,
            provider           TEXT NOT NULL,
            provider_id        TEXT NOT NULL,
            display_name       TEXT NOT NULL DEFAULT '',
            username           TEXT NOT NULL DEFAULT '',
            username_lower     TEXT NOT NULL DEFAULT '',
            country            TEXT NOT NULL DEFAULT '',
            avatar_url         TEXT NOT NULL DEFAULT '',
            color_index        INTEGER NOT NULL DEFAULT 0,
            session_id         TEXT,
            device_fingerprint TEXT,
            muted_until        TEXT,
            mute_count         INTEGER NOT NULL DEFAULT 0,
            created_at         TEXT NOT NULL,
            last_seen          TEXT,
            last_active        TEXT,
            UNIQUE (provider, provider_id)
        );
        CREATE UNIQUE INDEX IF NOT EXISTS idx_users_username ON users(username_lower) WHERE username_lower != '';

        CREATE TABLE IF NOT EXISTS sessions (
            id         TEXT PRIMARY KEY,
            user_id    TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            token      TEXT NOT NULL UNIQUE,
            expires_at TEXT NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_sessions_token ON sessions(token);
        CREATE INDEX IF NOT EXISTS idx_sessions_expires ON sessions(expires_at);

        CREATE TABLE IF NOT EXISTS email_tokens (
            token      TEXT PRIMARY KEY,
            email      TEXT NOT NULL,
            provider_id TEXT NOT NULL,
            fingerprint TEXT,
            expires_at TEXT NOT NULL
        );

        CREATE TABLE IF NOT EXISTS user_providers (
            user_id     TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            provider    TEXT NOT NULL,
            provider_id TEXT NOT NULL,
            created_at  TEXT NOT NULL,
            UNIQUE (provider, provider_id)
        );
        CREATE INDEX IF NOT EXISTS idx_user_providers_user ON user_providers(user_id);

        CREATE TABLE IF NOT EXISTS bans (
            id                 TEXT PRIMARY KEY,
            user_id            TEXT,
            provider           TEXT NOT NULL,
            provider_id        TEXT NOT NULL,
            device_fingerprint TEXT,
            reason             TEXT NOT NULL,
            created_at         TEXT NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_bans_provider ON bans(provider, provider_id);
        CREATE INDEX IF NOT EXISTS idx_bans_fingerprint ON bans(device_fingerprint);

        CREATE TABLE IF NOT EXISTS rooms (
            id            TEXT PRIMARY KEY,
            event_id      TEXT NOT NULL,
            type          TEXT NOT NULL,
            name          TEXT NOT NULL,
            description   TEXT NOT NULL DEFAULT '',
            is_main       INTEGER NOT NULL DEFAULT 0,
            is_moderated  INTEGER NOT NULL DEFAULT 1,
            is_read_only  INTEGER NOT NULL DEFAULT 0,
            auto_join     INTEGER NOT NULL DEFAULT 0,
            allows_media  INTEGER NOT NULL DEFAULT 1,
            ttl_minutes   INTEGER DEFAULT 60,
            position      INTEGER NOT NULL DEFAULT 0,
            created_at    TEXT NOT NULL,
            last_message_at TEXT
        );

        CREATE TABLE IF NOT EXISTS room_memberships (
            user_id      TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            room_id      TEXT NOT NULL REFERENCES rooms(id) ON DELETE CASCADE,
            joined_at    TEXT NOT NULL,
            last_read_at TEXT NOT NULL,
            PRIMARY KEY (user_id, room_id)
        );
        CREATE INDEX IF NOT EXISTS idx_memberships_user ON room_memberships(user_id);

        CREATE TABLE IF NOT EXISTS messages (
            id           TEXT PRIMARY KEY,
            room_id      TEXT NOT NULL REFERENCES rooms(id) ON DELETE CASCADE,
            user_id      TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            type         TEXT NOT NULL,
            content      TEXT NOT NULL,
            link_preview TEXT,
            reply_to_id  TEXT REFERENCES messages(id) ON DELETE SET NULL,
            media_url    TEXT,
            expires_at   TEXT NOT NULL,
            created_at   TEXT NOT NULL,
            moderation_status TEXT NOT NULL DEFAULT 'approved'
        );
        CREATE INDEX IF NOT EXISTS idx_messages_expires ON messages(expires_at);
        CREATE INDEX IF NOT EXISTS idx_messages_room ON messages(room_id, created_at);

        CREATE TABLE IF NOT EXISTS message_reactions (
            message_id TEXT NOT NULL REFERENCES messages(id) ON DELETE CASCADE,
            user_id    TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            emoji      TEXT NOT NULL,
            created_at TEXT NOT NULL,
            PRIMARY KEY (message_id, user_id, emoji)
        );
        CREATE INDEX IF NOT EXISTS idx_reactions_message ON message_reactions(message_id);

        CREATE TABLE IF NOT EXISTS meetups (
            id             TEXT PRIMARY KEY,
            creator_id     TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            stage_id       TEXT,
            title          TEXT NOT NULL,
            location_lat   REAL,
            location_lng   REAL,
            location_label TEXT,
            meetup_time    TEXT NOT NULL,
            note           TEXT,
            created_at     TEXT NOT NULL,
            expires_at     TEXT NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_meetups_expires ON meetups(expires_at);

        CREATE TABLE IF NOT EXISTS meetup_attendees (
            meetup_id TEXT NOT NULL REFERENCES meetups(id) ON DELETE CASCADE,
            user_id   TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            joined_at TEXT NOT NULL,
            PRIMARY KEY (meetup_id, user_id)
        );

        CREATE TABLE IF NOT EXISTS dm_participants (
            room_id TEXT NOT NULL REFERENCES rooms(id) ON DELETE CASCADE,
            user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            PRIMARY KEY (room_id, user_id)
        );

        CREATE TABLE IF NOT EXISTS blocks (
            blocker_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            blocked_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            created_at TEXT NOT NULL,
            PRIMARY KEY (blocker_id, blocked_id)
        );

        CREATE TABLE IF NOT EXISTS reports (
            id               TEXT PRIMARY KEY,
            reporter_id      TEXT NOT NULL,
            reported_user_id TEXT NOT NULL,
            message_snapshot TEXT NOT NULL,
            room_id          TEXT NOT NULL,
            reason           TEXT NOT NULL,
            status           TEXT NOT NULL DEFAULT 'pending',
            unverified       INTEGER NOT NULL DEFAULT 0,
            created_at       TEXT NOT NULL,
            reviewed_at      TEXT
        );

        CREATE TABLE IF NOT EXISTS strikes (
            id         TEXT PRIMARY KEY,
            user_id    TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            reason     TEXT NOT NULL,
            detail     TEXT,
            created_at TEXT NOT NULL,
            expires_at TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_strikes_user ON strikes(user_id);

        CREATE TABLE IF NOT EXISTS chat_push_subscriptions (
            id         INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id    TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            endpoint   TEXT NOT NULL UNIQUE,
            p256dh     TEXT NOT NULL,
            auth       TEXT NOT NULL,
            created_at TEXT NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_chat_push_user ON chat_push_subscriptions(user_id);

        CREATE TABLE IF NOT EXISTS e2ee_device_keys (
            user_id    TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            device_id  TEXT NOT NULL,
            public_key TEXT NOT NULL,
            created_at TEXT NOT NULL,
            last_seen  TEXT NOT NULL,
            PRIMARY KEY (user_id, device_id)
        );

        CREATE TABLE IF NOT EXISTS avatars (
            user_id TEXT PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE,
            data    BLOB NOT NULL
        );

        CREATE TABLE IF NOT EXISTS chat_settings (
            key   TEXT PRIMARY KEY,
            value TEXT NOT NULL
        );
        INSERT OR IGNORE INTO chat_settings (key, value) VALUES ('room_sort', 'auto');
        INSERT OR IGNORE INTO chat_settings (key, value) VALUES ('msg_char_limit', '1000');
        INSERT OR IGNORE INTO chat_settings (key, value) VALUES ('dm_ttl_minutes', '1440');
        INSERT OR IGNORE INTO chat_settings (key, value) VALUES ('room_ttl_minutes', '1440');
        INSERT OR IGNORE INTO chat_settings (key, value) VALUES ('meetup_ttl_minutes', '60');
    """)
    db.commit()


def get_setting(db: sqlite3.Connection, key: str, default: str = "") -> str:
    row = db.execute("SELECT value FROM chat_settings WHERE key = ?", (key,)).fetchone()
    return row["value"] if row else default


def set_setting(db: sqlite3.Connection, key: str, value: str) -> None:
    db.execute(
        "INSERT INTO chat_settings (key, value) VALUES (?, ?) "
        "ON CONFLICT(key) DO UPDATE SET value = excluded.value",
        (key, value),
    )
    db.commit()


def _migrate_chat_db(db: sqlite3.Connection) -> None:
    cols = {r[1] for r in db.execute("PRAGMA table_info(messages)").fetchall()}
    if "link_preview" not in cols:
        db.execute("ALTER TABLE messages ADD COLUMN link_preview TEXT")
        db.commit()
    if "media_url" not in cols:
        db.execute("ALTER TABLE messages ADD COLUMN media_url TEXT")

_purge_cycle = 0


async def purge_loop() -> None:
    global _purge_cycle
    while True:
        db = None
        try:
            db = get_chat_db()
            expired_msgs = purge_expired_messages(db)
            for batch in expired_msgs:
                await manager.broadcast_to_room(
                    batch["room_id"],
                    {
                        "event": "messages_expired",
                        "room_id": batch["room_id"],
                        "message_ids": batch["message_ids"],
                    },
                )

            expired_meetups = purge_expired_meetups(db)
            for meetup_id in expired_meetups:
                await manager.broadcast_to_room(
                    meetup_id,
                    {
                        "event": "meetup_expired",
                        "meetup_id": meetup_id,
                    },
                )
                manager.rooms.pop(meetup_id, None)
                manager._room_meta.pop(meetup_id, None)

            purge_expired_sessions(db)
            purge_old_reports(db)
            purge_expired_strikes(db)

            empty_dms = db.execute(
                "SELECT r.id FROM rooms r "
                "WHERE r.type = 'dm' AND r.last_message_at IS NULL AND NOT EXISTS ("
                "  SELECT 1 FROM messages m WHERE m.room_id = r.id"
                ")"
            ).fetchall()
            for row in empty_dms:
                db.execute(
                    "DELETE FROM dm_participants WHERE room_id = ?", (row["id"],)
                )
                db.execute(
                    "DELETE FROM room_memberships WHERE room_id = ?", (row["id"],)
                )
                db.execute("DELETE FROM rooms WHERE id = ?", (row["id"],))
                manager.rooms.pop(row["id"], None)
                manager._room_meta.pop(row["id"], None)
            if empty_dms:
                db.commit()

            _purge_cycle += 1

            if _purge_cycle % 120 == 0:
                db.execute("PRAGMA wal_checkpoint(TRUNCATE)")

            if _purge_cycle % 2880 == 0:
                purge_stale_push_subscriptions(db)

            if _purge_cycle % 240 == 0:
                cutoff = time.monotonic() - 7200
                stale_keys = [k for k, v in _push_debounce.items() if v < cutoff]
                for k in stale_keys:
                    _push_debounce.pop(k, None)
                    _push_sent.pop(k, None)
                    t = _push_flush_tasks.pop(k, None)
                    if t:
                        t.cancel()
                connected = set(manager.user_conns.keys())
                stale_activity = [
                    uid
                    for uid in list(manager._last_ws_activity)
                    if uid not in connected
                    and time.monotonic() - manager._last_ws_activity.get(uid, 0) > 7200
                ]
                for uid in stale_activity:
                    manager._last_ws_activity.pop(uid, None)

        except Exception:
            logger.exception("Purge loop error")
        finally:
            if db:
                db.close()
        await asyncio.sleep(30)

